1	/**
2	 * nsg program — dynamic Commander setup.
3	 *
4	 * Two command sources:
5	 *
6	 * 1. **Framework commands** — hardcoded in the CLI package (init, status,
7	 *    version, upgrade, plugin management). Always available, even without
8	 *    a guild.
9	 *
10	 * 2. **Plugin tools** — discovered at runtime via The Instrumentarium
11	 *    (tools apparatus). Only available when a guild is present and the
12	 *    tools apparatus is installed.
13	 *
14	 * Tool names are auto-grouped when multiple tools share a hyphen prefix:
15	 * 'plugin-list' + 'plugin-install' → 'nsg plugin list' / 'nsg plugin install'.
16	 * A tool like 'show-writ' stays flat ('nsg show-writ') since no other tool
17	 * starts with 'show-'.
18	 */
19	
20	import path from 'node:path';
21	import { Command } from 'commander';
22	import { z } from 'zod';
23	import { findGuildRoot, guild } from '@shardworks/nexus-core';
24	import type { ToolDefinition, InstrumentariumApi } from '@shardworks/tools-apparatus';
25	import { createGuild } from '@shardworks/nexus-arbor';
26	import { frameworkCommands } from './commands/index.ts';
27	import { toFlag, isBooleanSchema, findGroupPrefixes } from './helpers.ts';
28	
29	type ZodShape = Record<string, z.ZodTypeAny>;
30	
31	/**
32	 * Build a Commander command from a ToolDefinition.
33	 *
34	 * Generates options from the Zod param shape. Commander converts kebab-case
35	 * flags back to camelCase in opts(), matching the tool's schema keys directly.
36	 *
37	 * The action handler validates params through the tool's Zod schema before
38	 * calling the handler — Zod error messages are surfaced cleanly.
39	 */
40	function buildToolCommand(
41	  commandName: string,
42	  toolDef: ToolDefinition,
43	): Command {
44	  const cmd = new Command(commandName).description(toolDef.description);
45	
46	  const shape = toolDef.params.shape as ZodShape;
47	  for (const [key, schema] of Object.entries(shape)) {
48	    const flag = toFlag(key);
49	    const description = schema.description ?? key;
50	
51	    if (isBooleanSchema(schema)) {
52	      // Boolean flags: --flag (no <value>), sets to true when present
53	      cmd.option(flag, description);
54	    } else if (schema.isOptional()) {
55	      cmd.option(`${flag} <value>`, description);
56	    } else {
57	      cmd.requiredOption(`${flag} <value>`, description);
58	    }
59	  }
60	
61	  cmd.action(async (opts: Record<string, string | undefined>) => {
62	    try {
63	      const validated = toolDef.params.parse(opts);
64	      const result = await toolDef.handler(validated);
65	
66	      const output =
67	        typeof result === 'string' ? result : JSON.stringify(result, null, 2);
68	      console.log(output);
69	    } catch (err) {
70	      const message = err instanceof Error ? err.message : String(err);
71	      console.error(`Error: ${message}`);
72	      process.exit(1);
73	    }
74	  });
75	
76	  return cmd;
77	}
78	
79	/**
80	 * Register tool definitions as Commander commands.
81	 *
82	 * Tools whose hyphen prefix appears in `groupPrefixes` are nested:
83	 * 'plugin-list' → 'nsg plugin list'.
84	 *
85	 * All other tools are registered flat:
86	 * 'show-writ' → 'nsg show-writ'.
87	 * 'signal' → 'nsg signal'.
88	 */
89	function registerTools(
90	  program: Command,
91	  tools: ToolDefinition[],
92	): void {
93	  const groupPrefixes = findGroupPrefixes(tools);
94	  const groups = new Map<string, Command>();
95	
96	  for (const toolDef of tools) {
97	    const idx = toolDef.name.indexOf('-');
98	
99	    // No hyphen, or prefix doesn't qualify as a group → flat command
100	    if (idx === -1 || !groupPrefixes.has(toolDef.name.slice(0, idx))) {
101	      program.addCommand(buildToolCommand(toolDef.name, toolDef));
102	      continue;
103	    }
104	
105	    // Nested: split on first hyphen
106	    const groupName = toolDef.name.slice(0, idx);
107	    const subName = toolDef.name.slice(idx + 1);
108	
109	    let group = groups.get(groupName);
110	    if (!group) {
111	      group = new Command(groupName).description(`${groupName} commands`);
112	      program.addCommand(group);
113	      groups.set(groupName, group);
114	    }
115	
116	    group.addCommand(buildToolCommand(subName, toolDef));
117	  }
118	}
119	
120	// ── Entry ──────────────────────────────────────────────────────────────
121	
122	export async function main(): Promise<void> {
123	  // Pre-parse to extract --guild-root before tool discovery.
124	  const pre = new Command()
125	    .option('--guild-root <path>', 'Guild root directory')
126	    .allowUnknownOption()
127	    .allowExcessArguments()
128	    .exitOverride()
129	    .configureOutput({ writeOut: () => {}, writeErr: () => {} });
130	
131	  try {
132	    pre.parse(process.argv);
133	  } catch {
134	    // Ignore errors — we only care about --guild-root
135	  }
136	
137	  const preOpts = pre.opts() as { guildRoot?: string };
138	
139	  const program = new Command('nsg')
140	    .description('Nexus Mk 2.1 — guild CLI')
141	    .option('--guild-root <path>', 'Guild root directory (default: auto-detect from cwd)');
142	
